def ensure_icons():
    ICONS_DIR.mkdir(parents=True, exist_ok=True)
    results = {}
    for name, filename in ICON_MAP.items():
        local_path = ICONS_DIR / filename
        if local_path.exists():
            results[name] = str(local_path)
            continue
        url = f"{ICON_CDN}/{filename}"
        try:
            req = urllib.request.Request(url, headers={"User-Agent": "Mozilla/5.0"})
            with urllib.request.urlopen(req, timeout=10) as resp:
                data = resp.read()
            local_path.write_bytes(data)
            results[name] = str(local_path)
        except Exception:
            svg_data = INLINE_SVGS.get(name)
            if svg_data:
                b64 = base64.b64encode(svg_data.encode()).decode()
                results[name] = f"data:image/svg+xml;base64,{b64}"
            else:
                results[name] = None
    return results


def get_icons():
    if not any((ICONS_DIR / f).exists() for f in ICON_MAP.values()):
        return ensure_icons()
    results = {}
    for name, filename in ICON_MAP.items():
        local_path = ICONS_DIR / filename
        if local_path.exists():
            results[name] = str(local_path)
        else:
            svg_data = INLINE_SVGS.get(name)
            if svg_data:
                b64 = base64.b64encode(svg_data.encode()).decode()
                results[name] = f"data:image/svg+xml;base64,{b64}"
            else:
                results[name] = None
    return results
